def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
    result = []
    for i in range(len(s)):
        if s[i] == a and s[i+len(a)] == b and i + len(a) <= len(s) - k:
            for j in range(i + len(a), i + len(a) + len(b), len(a) + len(b)):
                if s[j] == a and s[j + len(a)] == b and j + len(a) + len(b) <= len(s) - k:
                    result.append(j)
    return result

